   251→func (*AggregateExpr) Type() ValueType  { return ValueTypeVector }
   252→func (e *Call) Type() ValueType         { return e.Func.ReturnType }
   253→func (*MatrixSelector) Type() ValueType { return ValueTypeMatrix }
   254→func (*SubqueryExpr) Type() ValueType   { return ValueTypeMatrix }
   255→func (*NumberLiteral) Type() ValueType  { return ValueTypeScalar }
   256→func (e *ParenExpr) Type() ValueType    { return e.Expr.Type() }
   257→func (*StringLiteral) Type() ValueType  { return ValueTypeString }
   258→func (e *UnaryExpr) Type() ValueType    { return e.Expr.Type() }
   259→func (*VectorSelector) Type() ValueType { return ValueTypeVector }
   260→func (e *BinaryExpr) Type() ValueType {
   261→	if e.LHS.Type() == ValueTypeScalar && e.RHS.Type() == ValueTypeScalar {
   262→		return ValueTypeScalar
   263→	}
   264→	return ValueTypeVector
